import{_ as o,c as t,o as a,ae as n}from"./chunks/framework.C4iaU4jI.js";const m=JSON.parse('{"title":"Avenir(s) DSAV","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function s(r,e,d,l,c,h){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="avenir-s-dsav" tabindex="-1">Avenir(s) DSAV <a class="header-anchor" href="#avenir-s-dsav" aria-label="Permalink to &quot;Avenir(s) DSAV&quot;">‚Äã</a></h1><h2 id="what-is-dsav" tabindex="-1">What is DSAV? <a class="header-anchor" href="#what-is-dsav" aria-label="Permalink to &quot;What is DSAV?&quot;">‚Äã</a></h2><p>DSAV is the deisgn system for AVENIR(s) projects and consists of a <a href="https://v3.vuejs.org/" target="_blank" rel="noreferrer"><strong>Vue 3</strong></a> project in the form of a <strong>component library</strong>.</p><p>The code is <a href="https://github.com/avenirs-esr/avenirs-dsav/" target="_blank" rel="noreferrer">open and available on GitHub</a></p><h2 id="why-dsav" tabindex="-1">Why DSAV? <a class="header-anchor" href="#why-dsav" aria-label="Permalink to &quot;Why DSAV?&quot;">‚Äã</a></h2><p>The AVENIR(s) program has chosen its technical stack for the front end, based on Vue 3.</p><p>The AVENIR(s) program needs its own identity, hence this design system it will use on all its frontend projects.</p><h2 id="complete-documentation" tabindex="-1">Complete documentation <a class="header-anchor" href="#complete-documentation" aria-label="Permalink to &quot;Complete documentation&quot;">‚Äã</a></h2><p>You can find the complete documentation on our <a href="https://avenirs-esr.github.io/avenirs-dsav/" target="_blank" rel="noreferrer">github page</a>.</p><h2 id="storybook-demos" tabindex="-1">Storybook demos <a class="header-anchor" href="#storybook-demos" aria-label="Permalink to &quot;Storybook demos&quot;">‚Äã</a></h2><p>You can find examples of use and demo of the design system components on our <a href="https://avenirs-esr.github.io/avenirs-dsav/storybook/" target="_blank" rel="noreferrer">github page</a>.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">‚Äã</a></h2><p>In your project, run <code>npm install @√¶venirs-esr/avenirs-dsav</code>.</p><p>In order to make the style from <code>DSAV</code> work in your project, make sure to import the main <code>DSAV</code> style in your <code>main.ts</code> with the following : <code>import &#39;@avenirs-esr/avenirs-dsav/style.css&#39;</code>.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">‚Äã</a></h2><h3 id="deploying-a-new-npm-version" tabindex="-1">Deploying a new npm version <a class="header-anchor" href="#deploying-a-new-npm-version" aria-label="Permalink to &quot;Deploying a new npm version&quot;">‚Äã</a></h3><p>When your development is successfully merged in <code>develop</code> or <code>main</code>, you can run the job <code>Release new version to npm</code> and select the type of version bump : <code>patch</code>, <code>minor</code> or <code>release</code>.</p><h3 id="commit-conventions" tabindex="-1">Commit conventions <a class="header-anchor" href="#commit-conventions" aria-label="Permalink to &quot;Commit conventions&quot;">‚Äã</a></h3><p>This repository uses <a href="https://commitlint.js.org/" target="_blank" rel="noreferrer">Commitlint</a> to enforce consistent and conventional commit messages.</p><p>This setup extends the conventional commit configuration (<code>@commitlint/config-conventional</code>) and adds custom rules:</p><p>‚úÖ Allowed Commit Types</p><p>The following commit types are allowed:</p><ul><li><code>feat</code> ‚Äì A new feature</li><li><code>fix</code> ‚Äì A bug fix</li><li><code>docs</code> ‚Äì Documentation changes</li><li><code>refactor</code> ‚Äì Code refactoring (no feature or bug fix)</li><li><code>test</code> ‚Äì Adding or modifying tests</li><li><code>build</code> ‚Äì Changes to build tools or dependencies</li><li><code>revert</code> ‚Äì Revert a previous commit</li></ul><p>üîÝ Commit Message Rules</p><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th></tr></thead><tbody><tr><td><code>type-enum</code></td><td>Only allows the types listed above</td></tr><tr><td><code>type-case</code></td><td>Commit type must be <strong>lowercase</strong></td></tr><tr><td><code>type-empty</code></td><td>Commit type <strong>must not</strong> be empty</td></tr><tr><td><code>subject-case</code></td><td>No restriction on subject casing (rule is disabled for flexibility)</td></tr></tbody></table><p>‚úÖ Example Commit Messages</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat: add user login functionality</span></span>
<span class="line"><span>fix: handle null pointer in dashboard</span></span>
<span class="line"><span>docs: update installation guide</span></span></code></pre></div><h2 id="projects-using-dsav" tabindex="-1">Projects using DSAV <a class="header-anchor" href="#projects-using-dsav" aria-label="Permalink to &quot;Projects using DSAV&quot;">‚Äã</a></h2><ul><li><a href="https://github.com/avenirs-esr/avenirs-cofolio-client" target="_blank" rel="noreferrer">AVENIR(s) Cofolio</a>‚ÄØ: An ePortfolio for Higher Education and Research</li></ul>`,29)])])}const u=o(i,[["render",s]]);export{m as __pageData,u as default};
